import UIKit
import WebKit

class ViewController: UIViewController {

    @IBOutlet weak var webView: WKWebView!

    override func viewDidLoad() {
        super.viewDidLoad()

        let url = URL(string: "https://your-website.com")!
        let request = URLRequest(url: url)
        webView.load(request)

        webView.configuration.userContentController.add(self, name: "callNativeFunc")
        webView.configuration.userContentController.add(self, name: "cameraAccess")
        webView.configuration.userContentController.add(self, name: "pushNotification")

        WKWebViewConfiguration().processPool = WKProcessPool()

        let scriptSource = """
            function callNativeFunc() {
                window.webkit.messageHandlers.callNativeFunc.postMessage("Hello from web!");
            }
            function cameraAccess() {
                window.webkit.messageHandlers.cameraAccess.postMessage(true);
            }
            function pushNotification() {
                window.webkit.messageHandlers.pushNotification.postMessage({
                    title: 'Push notification title',
                    message: 'Push notification message'
                });
            }
        """
        webView.evaluateJavaScript(scriptSource, completionHandler: nil)

    }

}

extension ViewController: WKScriptMessageHandler {

    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        if let body = message.body as? [String: Any],
           let action = body["action"] as? String,
           let data = body["data"] as? [String: Any] {

            switch action {
